function runWhenFontsReady(e){var t=()=>{document.fonts&&document.fonts.ready?document.fonts.ready.then(()=>requestAnimationFrame(e)).catch(()=>requestAnimationFrame(e)):requestAnimationFrame(e)};"loading"===document.readyState?document.addEventListener("DOMContentLoaded",t,{once:!0}):t()}runWhenFontsReady(()=>{document.querySelectorAll(".js-blur-words").forEach(n=>{let o=n.textContent.trim().split(/\s+/);n.textContent="",o.forEach((e,t)=>{var r=document.createElement("span");r.className="blur-word",r.textContent=e,n.appendChild(r),t<o.length-1&&n.appendChild(document.createTextNode(" "))});var e=n.querySelectorAll(".blur-word");gsap.set(n,{visibility:"visible"}),gsap.fromTo(e,{filter:"blur(10px)",opacity:0,y:"0.15em"},{filter:"blur(0px)",opacity:1,y:"0em",duration:1.8,stagger:.08,ease:"power4.out"})})}),runWhenFontsReady(()=>{gsap.registerPlugin(ScrollTrigger),document.querySelectorAll(".blur-in").forEach(n=>{let o=n.textContent.trim().split(/\s+/);n.textContent="",o.forEach((e,t)=>{var r=document.createElement("span");r.className="blur-word",r.textContent=e,n.appendChild(r),t<o.length-1&&n.appendChild(document.createTextNode(" "))});var e=n.querySelectorAll(".blur-word");gsap.fromTo(e,{filter:"blur(10px)",opacity:0,y:"0.4em"},{filter:"blur(0px)",opacity:1,y:"0em",duration:2,stagger:.07,ease:"power4.out",scrollTrigger:{trigger:n,start:"top 85%",end:"top 40%",toggleActions:"play none none none",once:!0}})})});